// Receive scraped prospects and prepare for GHL import
const body = $input.first().json.body;
const prospects = body.prospects || [];
const city = body.city || 'Fayetteville';
const state = body.state || 'NC';
const routeNumber = body.route_number;
const zipCode = body.zip_code;

// Map to GHL contact format
const contacts = prospects.map(p => ({
  json: {
    // GHL contact fields
    firstName: p.contact_name ? p.contact_name.split(' ')[0] : '',
    lastName: p.contact_name ? p.contact_name.split(' ').slice(1).join(' ') : '',
    businessName: p.business_name,
    email: p.email || '',
    phone: p.phone || '',
    address1: p.address || '',
    city: p.city || city,
    state: p.state || state,
    postalCode: p.zip || zipCode,
    website: p.website || '',

    // Custom fields (create these in GHL)
    source: 'google_maps',
    category: p.category || '',
    googleRating: p.google_rating || '',
    reviewCount: p.review_count || 0,
    routeNumber: routeNumber || '',
    zipCode: zipCode || '',

    // Tags for GHL
    tags: [
      `city-${city.toLowerCase().replace(/\s/g, '-')}`,
      `route-${routeNumber}`,
      `zip-${zipCode}`,
      `category-${(p.category || 'other').toLowerCase()}`,
      'source-google-maps',
      'status-new'
    ]
  }
}));

return contacts;

const total = $input.all().length;
const success = $input.all().filter(item => item.json.data?.contact?.id).length;

return [{
  json: {
    success: true,
    total_received: total,
    contacts_created: success,
    message: `Synced ${success}/${total} contacts to GoHighLevel`
  }
}];
